  1	import * as React from 'react';
  2	import { useODFNamespaceSelector } from '@odf/core/redux';
  3	import { useGetInternalClusterDetails } from '@odf/core/redux/utils';
  4	import { namespaceResource } from '@odf/core/resources';
  5	import { BreakdownCardBody } from '@odf/shared/dashboards/breakdown-card/breakdown-body';
  6	import { getSelectOptions } from '@odf/shared/dashboards/breakdown-card/breakdown-dropdown';
  7	import ResourceDropdown from '@odf/shared/dropdown/ResourceDropdown';
  8	import { FieldLevelHelp } from '@odf/shared/generic/FieldLevelHelp';
  9	import {
 10	  useCustomPrometheusPoll,
 11	  usePrometheusBasePath,
 12	} from '@odf/shared/hooks/custom-prometheus-poll';
 13	import { NamespaceModel } from '@odf/shared/models';
 14	import {
 15	  BreakdownCardFields,
 16	  BreakdownCardFieldsWithParams,
 17	} from '@odf/shared/queries';
 18	import { getName } from '@odf/shared/selectors';
 19	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 20	import {
 21	  getInstantVectorStats,
 22	  humanizeBinaryBytes,
 23	  sortInstantVectorStats,
 24	} from '@odf/shared/utils';
 25	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
 26	import {
 27	  Card,
 28	  CardBody,
 29	  CardHeader,
 30	  CardTitle,
 31	  MenuToggle,
 32	  MenuToggleElement,
 33	  SelectList,
 34	  Select,
 35	  SelectProps,
 36	} from '@patternfly/react-core';
 37	import { useStorageClassQueryFilter } from '../../../hooks';
 38	import {
 39	  getBreakdownMetricsQuery,
 40	  CEPH_CAPACITY_BREAKDOWN_QUERIES,
 41	  StorageDashboardQuery,
 42	} from '../../../queries/ceph-storage';
 43	import { getStackChartStats } from '../../../utils/metrics';
 44	import './capacity-breakdown-card.scss';
 45	
 46	const modelByUsedQueryMap = {
 47	  [BreakdownCardFields.PROJECTS]: StorageDashboardQuery.PROJECTS_BY_USED,
 48	  [BreakdownCardFields.PODS]: StorageDashboardQuery.PODS_BY_USED,
 49	  [BreakdownCardFields.STORAGE_CLASSES]:
 50	    StorageDashboardQuery.STORAGE_CLASSES_BY_USED,
 51	  [BreakdownCardFieldsWithParams.PVCS]:
 52	    StorageDashboardQuery.PVC_NAMESPACES_BY_USED,
 53	};
 54	
 55	const modelByTotalQueryMap = {
 56	  [BreakdownCardFields.PROJECTS]: StorageDashboardQuery.PROJECTS_TOTAL_USED,
 57	  [BreakdownCardFields.PODS]: StorageDashboardQuery.PODS_TOTAL_USED,
 58	  [BreakdownCardFields.STORAGE_CLASSES]:
 59	    StorageDashboardQuery.STORAGE_CLASSES_TOTAL_USED,
 60	  [BreakdownCardFieldsWithParams.PVCS]:
 61	    StorageDashboardQuery.PVC_NAMESPACES_TOTAL_USED,
 62	};
 63	
 64	const getInitialSortedNs = (
 65	  allResources: K8sResourceCommon[]
 66	): K8sResourceCommon =>
 67	  allResources?.sort((a, b) => getName(a).localeCompare(getName(b)))[0];
 68	
 69	export const NamespaceDropdown: React.FC<{
 70	  setPVCNamespace: React.Dispatch<React.SetStateAction<string>>;
 71	}> = ({ setPVCNamespace }) => {
 72	  const { t } = useCustomTranslation();
 73	
 74	  const initialSelection = React.useCallback(
 75	    (allResources: K8sResourceCommon[]): K8sResourceCommon => {
 76	      const initialResource = getInitialSortedNs(allResources);
 77	      setPVCNamespace(getName(initialResource));
 78	      return initialResource;
 79	    },
 80	    [setPVCNamespace]
 81	  );
 82	
 83	  return (
 84	    <div className="odf-capacity-breakdown-card-pvc-namespace__header">
 85	      <div
 86	        id="odf-capacity-breakdown-card-pvc-namespace-title"
 87	        className="odf-capacity-breakdown-card-pvc-namespace__title"
 88	      >
 89	        {t('Select a namespace:')}
 90	      </div>
 91	      <ResourceDropdown<K8sResourceCommon>
 92	        className="odf-capacity-breakdown-card-pvc-namespace__dropdown"
 93	        resource={namespaceResource}
 94	        resourceModel={NamespaceModel}
 95	        initialSelection={initialSelection}
 96	        onSelect={(ns) => {
 97	          setPVCNamespace(getName(ns));
 98	        }}
 99	        data-test="odf-capacity-breakdown-card-pvc-namespace-dropdown"
100	      />
101	    </div>
102	  );
103	};
104	
105	export const DescriptionText: React.FC = () => {
106	  const { t } = useCustomTranslation();
107	
108	  return (
109	    <div className="odf-capacity-breakdown-card-pvc-description">
110	      {t('Only showing PVCs that are being mounted on an active pod')}
111	    </div>
112	  );
113	};
114	
115	export const TitleWithHelp: React.FC = () => {
116	  const { t } = useCustomTranslation();
117	
118	  return (
119	    <>
120	      {t('Requested capacity')}
121	      <FieldLevelHelp testId="breakdown-card-helper-text">
122	        {t(
123	          'This card shows the requested capacity for different Kubernetes resources. The figures shown represent the usable storage, meaning that data replication is not taken into consideration.'
124	        )}
125	      </FieldLevelHelp>
126	    </>
127	  );
128	};
129	
130	const BreakdownCard: React.FC = () => {
131	  const { t } = useCustomTranslation();
132	  const [metricType, setMetricType] = React.useState<
133	    BreakdownCardFields | BreakdownCardFieldsWithParams
134	  >(BreakdownCardFields.PROJECTS);
135	  const [isOpenBreakdownSelect, setBreakdownSelect] = React.useState(false);
136	  const [pvcNamespace, setPVCNamespace] = React.useState('');
137	
138	  // name of the created StorageClasses are prefix by StorageCluster name,
139	  // it is also the value of the "managedBy" label in the metrics.
140	  const { clusterNamespace: clusterNs, clusterName: ocsCluster } =
141	    useGetInternalClusterDetails();
142	
143	  const [scQueryfilter, scQueryfilterLoaded, scQueryfilterError] =
144	    useStorageClassQueryFilter(clusterNs);
145	
146	  const { queries, model, metric } = getBreakdownMetricsQuery(
147	    metricType,
148	    scQueryfilter,
149	    pvcNamespace,
150	    false,
151	    ocsCluster
152	  );
153	
154	  const { odfNamespace } = useODFNamespaceSelector();
155	
156	  const [modelByUsed, modelUsedError, modelUsedLoading] =
157	    useCustomPrometheusPoll({
158	      query: queries[modelByUsedQueryMap[metricType]],
159	      endpoint: 'api/v1/query' as any,
160	      basePath: usePrometheusBasePath(),
161	    });
162	  const [modelTotalUsed, modelTotalError, modalTotalLoading] =
163	    useCustomPrometheusPoll({
164	      query: queries[modelByTotalQueryMap[metricType]],
165	      endpoint: 'api/v1/query' as any,
166	      basePath: usePrometheusBasePath(),
167	    });
168	  const [cephUsedMetric, cephError, cephLoading] = useCustomPrometheusPoll({
169	    query: CEPH_CAPACITY_BREAKDOWN_QUERIES(scQueryfilter, ocsCluster)[
170	      StorageDashboardQuery.CEPH_CAPACITY_USED
171	    ],
172	    endpoint: 'api/v1/query' as any,
173	    basePath: usePrometheusBasePath(),
174	  });
175	
176	  const queriesLoadError =
177	    modelUsedError || modelTotalError || cephError || scQueryfilterError;
178	  const dataLoaded =
179	    !modelUsedLoading &&
180	    !modalTotalLoading &&
181	    !cephLoading &&
182	    scQueryfilterLoaded;
183	
184	  const humanize = humanizeBinaryBytes;
185	  const top6MetricsData = getInstantVectorStats(modelByUsed, metric);
186	  const top5SortedMetricsData = sortInstantVectorStats(top6MetricsData);
187	  const top5MetricsStats = getStackChartStats(top5SortedMetricsData, humanize);
188	  const metricTotal: string = modelTotalUsed?.data?.result?.[0]?.value?.[1];
189	  const cephUsed: string = cephUsedMetric?.data?.result?.[0]?.value?.[1];
190	
191	  const handleMetricsChange: SelectProps['onSelect'] = (_e, breakdown) => {
192	    setMetricType(breakdown as any);
193	    setBreakdownSelect(!isOpenBreakdownSelect);
194	  };
195	
196	  const dropdownOptions = [
197	    {
198	      name: t('Projects'),
199	      id: BreakdownCardFields.PROJECTS,
200	    },
201	    {
202	      name: t('Storage Classes'),
203	      id: BreakdownCardFields.STORAGE_CLASSES,
204	    },
205	    {
206	      name: t('Pods'),
207	      id: BreakdownCardFields.PODS,
208	    },
209	    {
210	      name: t('PersistentVolumeClaims'),
211	      id: BreakdownCardFieldsWithParams.PVCS,
212	    },
213	  ];
214	  const breakdownSelectItems = getSelectOptions(dropdownOptions);
215	
216	  const onToggleClick = () => {
217	    setBreakdownSelect(!isOpenBreakdownSelect);
218	  };
219	
220	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
221	    <MenuToggle
222	      ref={toggleRef}
223	      onClick={onToggleClick}
224	      isExpanded={isOpenBreakdownSelect}
225	      className="ceph-capacity-breakdown-card-header__dropdown"
226	      aria-label={t('Break By Dropdown')}
227	      isFullWidth
228	    >
229	      {metricType}
230	    </MenuToggle>
231	  );
232	
233	  return (
234	    <Card>
235	      <CardHeader>
236	        <div className="ceph-capacity-breakdown-card__header">
237	          <CardTitle id="breakdown-card-title">
238	            <TitleWithHelp />
239	          </CardTitle>
240	          <Select
241	            id="breakdown-card-metrics-dropdown"
242	            onSelect={handleMetricsChange}
243	            isOpen={isOpenBreakdownSelect}
244	            selected={metricType}
245	            toggle={toggle}
246	            shouldFocusToggleOnSelect
247	            popperProps={{ width: 'trigger' }}
248	            onOpenChange={(isOpen) => setBreakdownSelect(isOpen)}
249	          >
250	            <SelectList>{breakdownSelectItems}</SelectList>
251	          </Select>
252	        </div>
253	      </CardHeader>
254	      {metricType === BreakdownCardFieldsWithParams.PVCS && (
255	        <NamespaceDropdown setPVCNamespace={setPVCNamespace} />
256	      )}
257	      <CardBody className="ceph-capacity-breakdown-card__body">
258	        <BreakdownCardBody
259	          isLoading={!dataLoaded}
260	          hasLoadError={queriesLoadError}
261	          metricTotal={metricTotal}
262	          top5MetricsStats={top5MetricsStats}
263	          capacityUsed={cephUsed}
264	          metricModel={model}
265	          humanize={humanize}
266	          isPersistentInternal={true}
267	          odfNamespace={odfNamespace}
268	        />
269	        {metricType === BreakdownCardFieldsWithParams.PVCS &&
270	          !queriesLoadError &&
271	          top5MetricsStats.length > 0 &&
272	          cephUsed && <DescriptionText />}
273	      </CardBody>
274	    </Card>
275	  );
276	};
277	
278	export default BreakdownCard;

