151	    ocsCluster
152	  );
153	
154	  const { odfNamespace } = useODFNamespaceSelector();
155	
156	  const [modelByUsed, modelUsedError, modelUsedLoading] =
157	    useCustomPrometheusPoll({
158	      query: queries[modelByUsedQueryMap[metricType]],
159	      endpoint: 'api/v1/query' as any,
160	      basePath: usePrometheusBasePath(),
161	    });
162	  const [modelTotalUsed, modelTotalError, modalTotalLoading] =
163	    useCustomPrometheusPoll({
164	      query: queries[modelByTotalQueryMap[metricType]],
165	      endpoint: 'api/v1/query' as any,
166	      basePath: usePrometheusBasePath(),
167	    });
168	  const [cephUsedMetric, cephError, cephLoading] = useCustomPrometheusPoll({
169	    query: CEPH_CAPACITY_BREAKDOWN_QUERIES(scQueryfilter, ocsCluster)[
170	      StorageDashboardQuery.CEPH_CAPACITY_USED
171	    ],
172	    endpoint: 'api/v1/query' as any,
173	    basePath: usePrometheusBasePath(),
174	  });
175	
176	  const queriesLoadError =
177	    modelUsedError || modelTotalError || cephError || scQueryfilterError;
178	  const dataLoaded =
179	    !modelUsedLoading &&
180	    !modalTotalLoading &&
181	    !cephLoading &&
182	    scQueryfilterLoaded;
183	
184	  const humanize = humanizeBinaryBytes;
185	  const top6MetricsData = getInstantVectorStats(modelByUsed, metric);
186	  const top5SortedMetricsData = sortInstantVectorStats(top6MetricsData);
187	  const top5MetricsStats = getStackChartStats(top5SortedMetricsData, humanize);
188	  const metricTotal: string = modelTotalUsed?.data?.result?.[0]?.value?.[1];
189	  const cephUsed: string = cephUsedMetric?.data?.result?.[0]?.value?.[1];
190	
191	  const handleMetricsChange: SelectProps['onSelect'] = (_e, breakdown) => {
192	    setMetricType(breakdown as any);
193	    setBreakdownSelect(!isOpenBreakdownSelect);
194	  };
195	
196	  const dropdownOptions = [
197	    {
198	      name: t('Projects'),
199	      id: BreakdownCardFields.PROJECTS,
200	    },
201	    {
202	      name: t('Storage Classes'),
203	      id: BreakdownCardFields.STORAGE_CLASSES,
204	    },
205	    {
206	      name: t('Pods'),
207	      id: BreakdownCardFields.PODS,
208	    },
209	    {
210	      name: t('PersistentVolumeClaims'),
211	      id: BreakdownCardFieldsWithParams.PVCS,
212	    },
213	  ];
214	  const breakdownSelectItems = getSelectOptions(dropdownOptions);
215	
216	  const onToggleClick = () => {
217	    setBreakdownSelect(!isOpenBreakdownSelect);
218	  };
219	
220	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
221	    <MenuToggle
222	      ref={toggleRef}
223	      onClick={onToggleClick}
224	      isExpanded={isOpenBreakdownSelect}
225	      className="ceph-capacity-breakdown-card-header__dropdown"
226	      aria-label={t('Break By Dropdown')}
227	      isFullWidth
228	    >
229	      {metricType}
230	    </MenuToggle>
231	  );
232	
233	  return (
234	    <Card>
235	      <CardHeader className="ceph-capacity-breakdown-card__header">
236	        <CardTitle id="breakdown-card-title">
237	          <TitleWithHelp />
238	        </CardTitle>
239	        <Select
240	          id="breakdown-card-metrics-dropdown"
241	          onSelect={handleMetricsChange}
242	          isOpen={isOpenBreakdownSelect}
243	          selected={metricType}
244	          toggle={toggle}
245	          shouldFocusToggleOnSelect
246	          popperProps={{ width: 'trigger', appendTo: 'inline' }}
247	          onOpenChange={(isOpen) => setBreakdownSelect(isOpen)}
248	        >
249	          <SelectList>{breakdownSelectItems}</SelectList>
250	        </Select>
251	      </CardHeader>
252	      {metricType === BreakdownCardFieldsWithParams.PVCS && (
253	        <NamespaceDropdown setPVCNamespace={setPVCNamespace} />
254	      )}
255	      <CardBody className="ceph-capacity-breakdown-card__body">
256	        <BreakdownCardBody
257	          isLoading={!dataLoaded}
258	          hasLoadError={queriesLoadError}
259	          metricTotal={metricTotal}
260	          top5MetricsStats={top5MetricsStats}
261	          capacityUsed={cephUsed}
262	          metricModel={model}
263	          humanize={humanize}
264	          isPersistentInternal={true}
265	          odfNamespace={odfNamespace}
266	        />
267	        {metricType === BreakdownCardFieldsWithParams.PVCS &&
268	          !queriesLoadError &&
269	          top5MetricsStats.length > 0 &&
270	          cephUsed && <DescriptionText />}
271	      </CardBody>
272	    </Card>
273	  );
274	};
275	
276	export default BreakdownCard;

